import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { build } from 'esbuild';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, '..');

const entryFile = path.join(repoRoot, 'monitoring/shared/pq.source.js');
const outputFile = path.join(repoRoot, 'monitoring/shared/pq.js');

await build({
    entryPoints: [entryFile],
    outfile: outputFile,
    bundle: true,
    format: 'esm',
    platform: 'browser',
    target: ['es2022'],
    sourcemap: false,
    logLevel: 'info',
    banner: {
        js: '// Generated by npm run build-wallet-pq. Do not edit this file directly.',
    },
});